import functools
class Solution:
    def mergeStones(self, stones, k):
        n = len(stones)
        if (n - 1) % (k - 1) != 0:
            return -1
        pre = [0] * (n + 1)
        for i in range(n):
            pre[i + 1] = pre[i] + stones[i]
        INF = float('inf')
        @functools.lru_cache(maxsize=None)
        def best(i, j, piles):
            length = j - i + 1
            if length < piles:
                return INF
            if piles == 1:
                if length == 1:
                    return 0
                sub = best(i, j, k)
                if sub == INF:
                    return INF
                return sub + pre[j + 1] - pre[i]
            res = INF
            for m in range(i, j, k - 1):
                left = best(i, m, 1)
                right = best(m + 1, j, piles - 1)
                if left < INF and right < INF:
                    res = min(res, left + right)
            return res
        ans = best(0, n - 1, 1)
        return ans if ans < INF else -1

