            return -1
        pre = [0] * (n + 1)
        for i in range(n):
            pre[i + 1] = pre[i] + stones[i]
        INF = float('inf')
        dp = [[0] * n for _ in range(n)]
        for length in range(k, n + 1):
            for i in range(0, n - length + 1):
                j = i + length - 1
                dp[i][j] = INF
                for m in range(i, j, k - 1):
                    dp[i][j] = min(dp[i][j], dp[i][m] + dp[m + 1][j])
                if (length - 1) % (k - 1) == 0:
                    dp[i][j] += pre[j + 1] - pre[i]
        return dp[0][n - 1]

